import axios
from 'axios';

const API =
'http://localhost:5000/api/marks/student';


// ======================================
// GET STUDENT MARKS
// ======================================

export const getStudentMarks =
async () => {

  const token =
    localStorage.getItem('token');

  const response =
    await axios.get(

      API,

      {

        headers: {

          Authorization:
          `Bearer ${token}`

        }

      }

    );

  return response.data;

};
